-- helpers
local function _tfind(t,v) for i,x in t do if x==v then return i end end end
local function _tadd(t,v) if not _tfind(t,v) then table.insert(t,v) end end
local function _tremove(t,v) local i=_tfind(t,v); if i then table.remove(t,i) end end

-- ─────────────────────────────────────────────────────────────
-- [2] FAKE REMOTE FACTORIES
-- ─────────────────────────────────────────────────────────────
local function RF(fn) -- RemoteFunction stub
    return setmetatable({},{
        __index=function(_,k)
            if k=="InvokeServer" then return function(_,...) return fn(...) end end
            if k=="OnClientInvoke" then return nil end
        end
    })
end
local function RE(fn) -- RemoteEvent stub
    local cbs={}
    return setmetatable({},{
        __index=function(_,k)
            if k=="FireServer" then return function(_,...) if fn then fn(...) end end end
            if k=="OnClientEvent" then
                return {Connect=function(_,cb) table.insert(cbs,cb); return {Connected=true,Disconnect=function()end} end}
            end
        end,
        __newindex=function(_,k,v)end,
        _fire=function(_,...) for _,cb in cbs do task.spawn(cb,...) end end
    })
end
local function BF(fn) -- BindableFunction stub
    return {Invoke=function(_,...) return fn(...) end}
end

