	Full = UDim2.fromOffset(800, 450)
}

local LastPos = UDim2.fromScale(.5, .5)

local Status = {
	SettingState = false,
	CurrentOrientation = false,
	NowPlayingPanelScreen = "QueueList",
	PreparedForDisplay = false,
