-- Grab the freshly created Masters ScreenGui
local ui = pg:WaitForChild("Masters")



-- ─────────────────────────────────────────────────────────────
-- [8] RUN HANDLER  (LocalScript source via loadstring)
-- ─────────────────────────────────────────────────────────────
local handlerEnv = setmetatable({},{__index=getfenv(0)})

handlerEnv.require = function(obj)
    if type(obj)=="table" and obj._isMod then
        local m = _mc[obj._name]
        if m then return m end
        warn("[Masters] require: unknown module '"..tostring(obj._name).."'")
        return {}
    end
    -- fallback for real instances
    local ok,res = pcall(require, obj)
    if ok then return res end
    warn("[Masters] require fallback failed: "..tostring(res))
    return {}
end

handlerEnv.script = {
    Name="Handler", ClassName="LocalScript",
    Parent = ui,
    WaitForChild = function(_,k,t)
        local deadline = tick()+(t or 5)
        while tick()<deadline do
            local c = ui:FindFirstChild(k,true)
            if c then return c end
            task.wait()
        end
        return nil
    end,
}

handlerEnv.game = setmetatable({},{
    __index = function(_,k) return game[k] end,
    __newindex = function(_,k,v) game[k]=v end,
    __namecall = function(_,...)
        local a={...}; local m=table.remove(a)
        if m=="GetService" and a[1]=="ReplicatedStorage" then return fakeRS end
        return (game[m])(game, table.unpack(a))
    end
})



